import './App.css';
import { useState } from 'react';

function App() {
  const [searchTerm, setSearchTerm] = useState('');
  const [cars, setCars] = useState([]);

  const searchCars = async () => {
    if (!searchTerm) return;
    const response = await fetch(`http://localhost:5000/api/cars?s=${searchTerm}`);
    const data = await response.json();
    console.log('API response:', data);
    if (data.data) {
      setCars(data.data);
    } else {
      setCars([]);
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>Car Finder</h1>
        <div className="search-container">
          <input
            type="text"
            placeholder="Search for car brands..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <button onClick={searchCars}>Search</button>
        </div>
      </header>
      <main>
        <div className="cars-container">
          {cars.map((car) => (
            <div key={car.vehicle.vin} className="car-card">
              <img src={car.photos && car.photos[0] ? car.photos[0].url : 'https://via.placeholder.com/200x150?text=Car+Image'} alt={car.vehicle.model} />
              <h3>{car.vehicle.year} {car.vehicle.make} {car.vehicle.model}</h3>
              <p>Price: ${car.retailListing?.price?.toLocaleString()}</p>
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}

export default App;
